import React, { useEffect, useMemo, useState } from 'react';
import { useAppDispatch } from '../../store/hooks';
import { Button, Input, Modal, dispatchAppToast } from '@linm-soft/common-components';
import {
  SharedCatalogProposalFieldControl,
  getSharedCatalogProposalFields,
  type SharedCatalogProposalFieldDef,
} from './sharedCatalogProposalFieldRegistry';
import styles from '../../styles/erpPage.module.css';

export type SharedCatalogProposalMode = 'usage' | 'change';

export interface SharedCatalogProposalSubmitChange {
  action: 'Create' | 'Update' | 'Delete';
  reason: string;
  note?: string;
  fields: Record<string, unknown>;
}

export interface SharedCatalogProposalModalProps {
  testIdPrefix: string;
  isOpen: boolean;
  onClose: () => void;
  catalogKind: string;
  modes: SharedCatalogProposalMode[];
  context: 'catalog' | 'item';
  entityKey?: string;
  entityLabel?: string;
  defaultChangeAction?: 'Update' | 'Delete' | 'Create';
  currentValues?: Record<string, unknown>;
  onSubmitUsage: (note?: string) => Promise<void>;
  onSubmitChange: (payload: SharedCatalogProposalSubmitChange) => Promise<void>;
  /** Catalog toolbar — gửi kèm mã nhập trong modal. */
  onSubmitChangeWithKey?: (
    entityKey: string,
    payload: SharedCatalogProposalSubmitChange,
  ) => Promise<void>;
  /** BE ui-schema — overrides registry when set. */
  proposalFieldDefs?: SharedCatalogProposalFieldDef[];
}

function formatCurrentValue(value: unknown): string {
  if (value === true) return 'Có';
  if (value === false) return 'Không';
  if (value == null || value === '') return '—';
  return String(value);
}

export const SharedCatalogProposalModal: React.FC<SharedCatalogProposalModalProps> = ({
  testIdPrefix,
  isOpen,
  onClose,
  catalogKind,
  modes,
  context,
  entityKey: entityKeyProp,
  entityLabel,
  defaultChangeAction = 'Update',
  currentValues: currentValuesProp,
  onSubmitUsage,
  onSubmitChange,
  onSubmitChangeWithKey,
  proposalFieldDefs: proposalFieldDefsProp,
}) => {
  const dispatch = useAppDispatch();
  const showChange = modes.includes('change');
  const showUsage = modes.includes('usage');
  const stacked = showChange && showUsage;

  const [usageNote, setUsageNote] = useState('');
  const [reason, setReason] = useState('');
  const [changeAction, setChangeAction] = useState<'Create' | 'Update' | 'Delete'>(defaultChangeAction);
  const [selectedKeys, setSelectedKeys] = useState<Set<string>>(new Set());
  const [fieldValues, setFieldValues] = useState<Record<string, unknown>>({});
  const [submittingUsage, setSubmittingUsage] = useState(false);
  const [submittingChange, setSubmittingChange] = useState(false);

  const fieldDefs = useMemo(
    () => proposalFieldDefsProp?.length
      ? proposalFieldDefsProp
      : getSharedCatalogProposalFields(catalogKind),
    [catalogKind, proposalFieldDefsProp],
  );
  const resolvedEntityKey = (entityKeyProp ?? '').trim();

  /** Reset form only when modal opens — avoid `currentValues = {}` default breaking controlled inputs. */
  useEffect(() => {
    if (!isOpen) return;
    const cv = currentValuesProp ?? {};
    setUsageNote('');
    setReason('');
    setChangeAction(defaultChangeAction);
    const defaults = fieldDefs.reduce<Record<string, unknown>>((acc, f) => {
      acc[f.key] = cv[f.key] ?? (f.type === 'boolean' ? false : '');
      return acc;
    }, {});
    setFieldValues(defaults);
    setSelectedKeys(new Set(fieldDefs.map(f => f.key)));
    // eslint-disable-next-line react-hooks/exhaustive-deps -- init on open only
  }, [isOpen]);

  const toggleField = (key: string) => {
    setSelectedKeys(prev => {
      const next = new Set(prev);
      if (next.has(key)) next.delete(key);
      else next.add(key);
      return next;
    });
  };

  const submitUsage = async () => {
    setSubmittingUsage(true);
    try {
      await onSubmitUsage(usageNote.trim() || undefined);
      onClose();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: err instanceof Error ? err.message : 'Gửi đề xuất dùng chung thất bại',
        type: 'error',
      });
    } finally {
      setSubmittingUsage(false);
    }
  };

  const submitChange = async () => {
    if (!reason.trim()) {
      dispatchAppToast(dispatch, { message: 'Nhập lý do đề xuất sửa đổi', type: 'error' });
      return;
    }
    if (!resolvedEntityKey) {
      dispatchAppToast(dispatch, { message: 'Nhập mã bản ghi cần đề xuất sửa', type: 'error' });
      return;
    }
    if (changeAction !== 'Delete' && selectedKeys.size === 0) {
      dispatchAppToast(dispatch, { message: 'Chọn ít nhất một trường trong lưới đề xuất', type: 'error' });
      return;
    }
    setSubmittingChange(true);
    try {
      const fields: Record<string, unknown> = {};
      selectedKeys.forEach(key => {
        fields[key] = fieldValues[key];
      });
      const payload: SharedCatalogProposalSubmitChange = {
        action: changeAction,
        reason: reason.trim(),
        note: usageNote.trim() || undefined,
        fields,
      };
      if (onSubmitChangeWithKey) {
        await onSubmitChangeWithKey(resolvedEntityKey, payload);
      } else {
        await onSubmitChange(payload);
      }
      onClose();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: err instanceof Error ? err.message : 'Gửi đề xuất sửa đổi thất bại',
        type: 'error',
      });
    } finally {
      setSubmittingChange(false);
    }
  };

  const title = entityKeyProp
    ? `Đề xuất — ${entityLabel ?? entityKeyProp}`
    : 'Đề xuất — danh mục dùng chung';

  const changeSection = showChange ? (
    <section
      className={styles.sharedProposalSection}
      data-testid={`${testIdPrefix}-proposal-section-change`}
    >
      <h3 className={styles.sharedProposalSectionTitle}>1. Đề xuất sửa đổi</h3>
      <p className={styles.sharedCatalogHint}>
        Chọn trường và giá trị đề xuất — chờ người có quyền phê duyệt áp dụng lên danh mục dùng chung.
      </p>
      {entityKeyProp && (
        <p className={styles.sharedCatalogHint} data-testid={`${testIdPrefix}-proposal-entity`}>
          Mã: <code>{entityKeyProp}</code>
          {entityLabel ? ` · ${entityLabel}` : ''}
        </p>
      )}
      <div className={styles.field}>
        <Input
          label="Lý do đề xuất *"
          value={reason}
          data-testid={`${testIdPrefix}-proposal-reason`}
          onChange={e => setReason(e.target.value)}
        />
      </div>
      {context === 'item' && (
        <div className={styles.sharedProposalActionRow}>
          <span className={styles.label}>Thao tác:</span>
          <select
            className={styles.selectNative}
            value={changeAction}
            data-testid={`${testIdPrefix}-proposal-action`}
            onChange={e => setChangeAction(e.target.value as 'Create' | 'Update' | 'Delete')}
          >
            <option value="Update">Sửa thông tin</option>
            <option value="Delete">Ngưng / xóa</option>
            <option value="Create">Đưa vào dùng chung</option>
          </select>
        </div>
      )}
      {changeAction !== 'Delete' && (
        <div className={styles.sharedProposalFieldGrid}>
          <div className={styles.sharedProposalGridHead3}>
            <span>Trường</span>
            <span>Giá trị hiện tại</span>
            <span>Giá trị đề xuất</span>
          </div>
          {fieldDefs.map(def => (
            <div key={def.key} className={styles.sharedProposalGridRow3}>
              <label className={styles.sharedProposalFieldPick}>
                <input
                  type="checkbox"
                  checked={selectedKeys.has(def.key)}
                  onChange={() => toggleField(def.key)}
                />
                {def.label}
              </label>
              <span className={styles.sharedProposalCurrentValue}>
                {formatCurrentValue((currentValuesProp ?? {})[def.key])}
              </span>
              <SharedCatalogProposalFieldControl
                def={def}
                value={fieldValues[def.key]}
                disabled={!selectedKeys.has(def.key)}
                hideLabel
                testIdPrefix={testIdPrefix}
                onChange={(key, val) => setFieldValues(prev => ({ ...prev, [key]: val }))}
              />
            </div>
          ))}
        </div>
      )}
      {stacked && (
        <div className={styles.sharedProposalSectionActions}>
          <Button
            variant="primary"
            size="sm"
            disabled={submittingChange || submittingUsage}
            data-testid={`${testIdPrefix}-proposal-submit-change`}
            onClick={() => void submitChange()}
          >
            {submittingChange ? 'Đang gửi…' : 'Gửi đề xuất sửa đổi'}
          </Button>
        </div>
      )}
    </section>
  ) : null;

  const usageSection = showUsage ? (
    <section
      className={styles.sharedProposalSection}
      data-testid={`${testIdPrefix}-proposal-section-usage`}
    >
      <h3 className={styles.sharedProposalSectionTitle}>
        {stacked ? '2. Đề xuất dùng chung' : 'Đề xuất dùng chung'}
      </h3>
      <p className={styles.sharedCatalogHint}>
        {context === 'catalog'
          ? 'Gửi yêu cầu kích hoạt pool danh mục dùng chung cho đơn vị — chờ người duyệt.'
          : 'Đề xuất đưa bản ghi này vào danh mục dùng chung — chờ người duyệt.'}
      </p>
      <div className={styles.field}>
        <Input
          label="Ghi chú (tùy chọn)"
          value={usageNote}
          placeholder="Lý do / ghi chú thêm"
          data-testid={`${testIdPrefix}-proposal-usage-note`}
          onChange={e => setUsageNote(e.target.value)}
        />
      </div>
      {stacked && (
        <div className={styles.sharedProposalSectionActions}>
          <Button
            variant="primary"
            size="sm"
            disabled={submittingUsage || submittingChange}
            data-testid={`${testIdPrefix}-proposal-submit-usage`}
            onClick={() => void submitUsage()}
          >
            {submittingUsage ? 'Đang gửi…' : 'Gửi đề xuất dùng chung'}
          </Button>
        </div>
      )}
    </section>
  ) : null;

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title={title}
      size="lg"
      data-testid={`${testIdPrefix}-proposal-modal`}
    >
      <div className={styles.sharedProposalBody}>
        {stacked ? (
          <>
            {changeSection}
            <hr className={styles.sharedProposalDivider} />
            {usageSection}
          </>
        ) : (
          <>
            {changeSection}
            {usageSection}
          </>
        )}
      </div>
      <div className={styles.modalFooterBar}>
        <Button variant="secondary" onClick={onClose} disabled={submittingUsage || submittingChange}>
          Hủy
        </Button>
        {!stacked && showUsage && !showChange && (
          <Button
            variant="primary"
            disabled={submittingUsage}
            data-testid={`${testIdPrefix}-proposal-submit`}
            onClick={() => void submitUsage()}
          >
            {submittingUsage ? 'Đang gửi…' : 'Gửi đề xuất dùng chung'}
          </Button>
        )}
        {!stacked && showChange && !showUsage && (
          <Button
            variant="primary"
            disabled={submittingChange}
            data-testid={`${testIdPrefix}-proposal-submit`}
            onClick={() => void submitChange()}
          >
            {submittingChange ? 'Đang gửi…' : 'Gửi đề xuất sửa đổi'}
          </Button>
        )}
      </div>
    </Modal>
  );
};
